




























import Vue from 'vue';

export default Vue.extend({
  name: 'ProjectCard',
  props: {
    title: {
      type: String,
      required: true,
    },
    body: {
      type: String,
      required: true,
    },
    link: {
      type: String,
      required: false,
    },
  },
  methods: {
    learnMore() {
      if (this.link) {
        window.location.href = this.link;
      }
    },
  },
  computed: {
    getBodyText(): string {
      if (this.body) return this.body;
      return 'No information';
    },
  },
});
